interface Speakable {
    void speak();          // must be implemented
    String getVoice();     // must be implemented
}

class Dog implements Speakable {
    private String name;
    Dog(String name) { this.name = name; }

    @Override
    public void speak() { System.out.println(name + " says: " + getVoice()); }

    @Override
    public String getVoice() { return "Woof!"; }
}

class Robot implements Speakable {
    @Override
    public void speak() { System.out.println("Robot says: " + getVoice()); }

    @Override
    public String getVoice() { return "BEEP BOOP"; }
}

public class Main {
    static void makeSpeak(Speakable s) {  // accepts ANY Speakable
        s.speak();
    }

    public static void main(String[] args) {
        makeSpeak(new Dog("Rex"));
        makeSpeak(new Robot());
    }
}

interface Swimmable { void swim(); }
interface Flyable   { void fly();  }

class Duck implements Swimmable, Flyable {
    private String name;
    Duck(String name) { this.name = name; }

    @Override public void swim() { System.out.println(name + " is swimming."); }
    @Override public void fly()  { System.out.println(name + " is flying.");  }
}

class Boat implements Swimmable {
    @Override public void swim() { System.out.println("Boat is sailing."); }
}

public class Main {
    public static void main(String[] args) {
        Duck duck = new Duck("Donald");
        duck.swim();
        duck.fly();

        // Duck IS-A Swimmable AND IS-A Flyable:
        Swimmable s = duck;
        Flyable   f = duck;
        s.swim();
        f.fly();
    }
}

interface Printable {
    String format();  // abstract — must implement

    default void print() {   // default — optional to override
        System.out.println("[PRINT] " + format());
    }

    default void printLoud() {
        System.out.println("[PRINT] " + format().toUpperCase());
    }
}

class Invoice implements Printable {
    private int id;
    private double amount;
    Invoice(int id, double amount) { this.id=id; this.amount=amount; }

    @Override
    public String format() {
        return String.format("Invoice #%d: $%.2f", id, amount);
    }
    // Uses default print() and printLoud()
}

public class Main {
    public static void main(String[] args) {
        Invoice inv = new Invoice(1001, 89.99);
        inv.print();
        inv.printLoud();
    }
}

