@FunctionalInterface
interface MathOp {
    double apply(double a, double b);
}

public class Main {
    static double calculate(double a, double b, MathOp op) {
        return op.apply(a, b);
    }

    public static void main(String[] args) {
        MathOp add      = (a, b) -> a + b;
        MathOp subtract = (a, b) -> a - b;
        MathOp multiply = (a, b) -> a * b;
        MathOp power    = (a, b) -> Math.pow(a, b);

        System.out.println(calculate(10, 3, add));
        System.out.println(calculate(10, 3, subtract));
        System.out.println(calculate(10, 3, multiply));
        System.out.println(calculate(2, 10, power));
    }
}
